class Solution {
public:
    int canBeTypedWords(string text, string brokenLetters) {
        unordered_set<char> brokenSet(brokenLetters.begin(), brokenLetters.end());
        int count = 0;
        string word;
        for (char c : text) {
            if (c == ' ') {
                word.clear();
                count++;
            } else {
                word += c;
                if (brokenSet.count(c)) {
                    return count;
                }
            }
        }
        return count + 1;
    }
};
```
